# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.sharetarget

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.webkit.URLUtil
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareTargetActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleShareIntent(intent)
        finish()
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        if (intent != null) {
            handleShareIntent(intent)
            finish()
        }
    }

    private fun handleShareIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> handleSingleShare(intent)
            Intent.ACTION_SEND_MULTIPLE -> handleMultipleShare(intent)
        }
    }

    private fun handleSingleShare(intent: Intent) {
        when (intent.type) {
            "text/plain" -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                val sharedUrl = extractUrl(sharedText)
                processSharedContent(sharedUrl ?: sharedText)
            }

            in listOf("image/*", "image/png", "image/jpeg", "image/jpg", "image/webp") -> {
                val sharedImageUri: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
                if (sharedImageUri != null) {
                    processSharedContent(sharedImageUri.toString())
                }
            }

            else -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                val sharedStream: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
                when {
                    sharedText != null -> processSharedContent(sharedText)
                    sharedStream != null -> processSharedContent(sharedStream.toString())
                }
            }
        }
    }

    private fun handleMultipleShare(intent: Intent) {
        val sharedImages = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
        sharedImages?.forEach { uri ->
            processSharedContent(uri.toString())
        }
    }

    private fun extractUrl(text: String?): String? {
        if (text.isNullOrBlank()) return null
        val trimmed = text.trim()
        return if (URLUtil.isValidUrl(trimmed)) trimmed else null
    }

    private fun processSharedContent(content: String?) {
        if (content.isNullOrBlank()) return
        Toast.makeText(this, "Shared content: $content", Toast.LENGTH_LONG).show()
    }
}

